/**
 * AST Walker
 *
 * Simple recursive walker for oxc-parser ASTs. Visits every node in the tree
 * and calls type-specific callbacks. Drop-in replacement for oxc-parser's
 * Visitor class, which has CJS/ESM interop issues in Electron.
 *
 * Once oxc-parser's Visitor works in Electron, this can be swapped back.
 */

/**
 * Callbacks for specific AST node types.
 * Add more node types here as needed.
 */
export interface WalkCallbacks {
  JSXElement?: (node: any) => void;
  JSXFragment?: (node: any) => void;
}

/**
 * Recursively walks an oxc-parser AST, calling callbacks for matching node types.
 * Traverses all object properties and array elements depth-first.
 */
export function walk(node: unknown, callbacks: WalkCallbacks): void {
  if (node === null || node === undefined || typeof node !== "object") return;

  if (Array.isArray(node)) {
    for (const child of node) {
      walk(child, callbacks);
    }
    return;
  }

  const record = node as Record<string, unknown>;
  const type = record.type;

  if (typeof type === "string" && type in callbacks) {
    (callbacks as Record<string, (node: unknown) => void>)[type]!(node);
  }

  for (const value of Object.values(record)) {
    if (value !== null && typeof value === "object") {
      walk(value, callbacks);
    }
  }
}
