/**
 * Canvas source-version identity.
 *
 * `sourceVersionHash` maps the exact text of a source file to a 16-hex-character
 * token identifying that content. It is the version stamp the canvas edit/
 * reconcile loop uses to answer "has the host caught up to write W?": the SDK
 * JSX transforms stamp `data-tempo-source-version` with the hash of the source
 * they annotate, and the write pipeline (`applyWrites` → `sourceVersionsByFile`)
 * reports the hash of the exact bytes it wrote. A captured element's stamp is
 * compared for EQUALITY against a write's version — never ordered, never
 * subtracted, never used as a high-water mark. Two identical contents MUST
 * produce the same token; two different contents MUST (for identity purposes)
 * produce different tokens.
 *
 * Because coverage is an equality test across independently-computed hashes,
 * every producer of a version — this function's callers in the vite/next/expo
 * transforms and in `applyWrites` — MUST route through THIS function so the
 * tokens are bit-identical. Changing the algorithm requires changing it for all
 * producers in lockstep, or old stamps and new write-versions stop matching.
 *
 * The token concatenates two independent 32-bit rolling hashes over the string's
 * UTF-16 code units — djb2 and sdbm — each rendered as unsigned 8-char hex. Two
 * independent hash families make an accidental collision between distinct source
 * contents vanishingly unlikely for version-identity use, while the function
 * stays dependency-free and single-pass (fast enough to run once per file per
 * transform on the devserver hot path).
 */
export function sourceVersionHash(content: string): string {
  let djb2 = 5381;
  let sdbm = 0;
  for (let i = 0; i < content.length; i++) {
    const c = content.charCodeAt(i);
    // djb2: hash * 33 ^ c. The trailing `^ c` keeps the value inside 32-bit
    // signed range every iteration, so no explicit coercion is needed.
    djb2 = ((djb2 << 5) + djb2) ^ c;
    // sdbm: c + hash*65599. The final term is an arithmetic subtraction, so
    // coerce back to a 32-bit int each step to prevent float drift.
    sdbm = (c + (sdbm << 6) + (sdbm << 16) - sdbm) | 0;
  }
  return toHex8(djb2) + toHex8(sdbm);
}

/** Render a 32-bit value as unsigned, zero-padded 8-char lowercase hex. */
function toHex8(n: number): string {
  return (n >>> 0).toString(16).padStart(8, "0");
}
