export type Range = {
  /** Start byte offset (inclusive). */
  start: number;
  /** End byte offset (exclusive). */
  end: number;
};

export const ScopeType = {
  Program: 'program',
  Function: 'function',
  Block: 'block',
  Catch: 'catch',
  Class: 'class',
  ClassStaticBlock: 'class-static',
  For: 'for',
  Switch: 'switch',
  TsModule: 'ts-module',
  Enum: 'enum',
  Type: 'type',
  TsConditional: 'ts-conditional',
} as const;

export type ScopeType = (typeof ScopeType)[keyof typeof ScopeType];

export const ScopeFlags = {
  Top: 1 << 0,
  Function: 1 << 1,
  Block: 1 << 2,
  Catch: 1 << 3,
  Class: 1 << 4,
  For: 1 << 5,
  Switch: 1 << 6,
  Module: 1 << 7,
  StrictMode: 1 << 8,
  ClassStaticBlock: 1 << 9,
  TsModuleBlock: 1 << 10,
  TsConditional: 1 << 11,
  Type: 1 << 12,
  Enum: 1 << 13,
} as const;

export type ScopeFlags = number;

export const BindingKind = {
  Var: 'var',
  Let: 'let',
  Const: 'const',
  Function: 'function',
  Class: 'class',
  Param: 'param',
  Import: 'import',
  TypeImport: 'type-import',
  TypeAlias: 'type-alias',
  Interface: 'interface',
  Enum: 'enum',
  EnumMember: 'enum-member',
  TypeParam: 'type-param',
  Namespace: 'namespace',
} as const;

export type BindingKind = (typeof BindingKind)[keyof typeof BindingKind];

export type Scope = {
  id: number;
  type: ScopeType;
  flags: ScopeFlags;
  start: number;
  end: number;
  parentId: number | null;
  childIds: number[];
  bindings: Map<string, number>;
  typeBindings: Map<string, number>;
};

export type Binding = {
  id: number;
  name: string;
  kind: BindingKind;
  declStart: number;
  declEnd: number;
  scopeId: number;
};

export type Reference = {
  id: number;
  name: string;
  start: number;
  end: number;
  scopeId: number;
  bindingId: number | null;
};

export type ScopeAnalysis = {
  source: string;
  scopes: Scope[];
  bindings: Binding[];
  references: Reference[];
};
