/**
 * Webpack-compatible loader that annotates JSX elements with Tempo's
 * `data-tempo-*` source-location metadata. Runs in both Webpack and Turbopack
 * via the rule registration done by `tempoNextjsPlugin` in `nextjs.ts`.
 *
 * Output parity with the Vite plugin (`./index.ts`) is exact — see SPEC_NEXTJS.md.
 */

import { realpathSync, statSync } from "node:fs";
import { createRequire } from "node:module";
import { sep, relative, resolve } from "node:path";

import {
  annotateFile,
  sourceVersionHash,
  type ElementInfo,
  type PropValue,
} from "@modules/annotation";
import { parseSync, type JSXElement } from "oxc-parser";
import { getTagName, walk } from "@modules/file-parser";

import { computeTempoAnnotatedProps } from "./annotation-strategy.ts";

const ROOT_META_NAME = "tempo-project-root";

export type ComputeAnnotatedProps = (
  info: ElementInfo,
  filepath: string,
  modifiedtsMs: number,
) => Record<string, PropValue>;

export interface NextjsLoaderOptions {
  /** Project-relative or absolute path to a module that default-exports a
   *  ComputeAnnotatedProps function. Resolved against `rootContext` on first
   *  invocation. */
  computeAnnotatedPropsModule?: string;
  /** Auto-inject `<meta name="tempo-project-root">` into JSX `<head>`. Default: true. */
  autoInjectRootMeta?: boolean;
}

/**
 * The loader receives webpack-style `this` context. Both Webpack and Turbopack
 * implement this same shape via `loader-runner`.
 */
interface LoaderContext {
  resourcePath: string;
  rootContext: string;
  cacheable?: (flag?: boolean) => void;
  getOptions?: () => NextjsLoaderOptions;
  query?: NextjsLoaderOptions | string;
}

// ---------------------------------------------------------------------------
// Module-level singletons. The loader file is required once per
// loader-runner process; these survive across loader invocations on the same
// worker.
// ---------------------------------------------------------------------------

let cachedCanonicalRoot: string | null = null;
let cachedUserComputeProps: ComputeAnnotatedProps | null | undefined;
let cachedComputeModulePath: string | null = null;

/** Reset cached singletons. Used by tests; never called in production. */
export function _resetLoaderState(): void {
  cachedCanonicalRoot = null;
  cachedUserComputeProps = undefined;
  cachedComputeModulePath = null;
}

// ---------------------------------------------------------------------------
// Path utilities.
// ---------------------------------------------------------------------------

function stripQueryAndHash(path: string): string {
  const queryIdx = path.indexOf("?");
  const hashIdx = path.indexOf("#");
  let end = path.length;
  if (queryIdx !== -1) end = Math.min(end, queryIdx);
  if (hashIdx !== -1) end = Math.min(end, hashIdx);
  return path.slice(0, end);
}

function resolveCanonicalRoot(rootContext: string): string {
  try {
    return realpathSync.native(rootContext);
  } catch {
    return rootContext;
  }
}

function isInNodeModules(path: string): boolean {
  return path.includes(`${sep}node_modules${sep}`);
}

// ---------------------------------------------------------------------------
// Root-meta injection. Splices a `<meta name="tempo-project-root">` element
// into the served document so consumers can reconstruct absolute paths from
// the relative `data-tempo-filepath` values.
//
// Placement, in order of preference:
//   1. As the first child of an existing JSX `<head>`.
//   2. Wrapped in a fresh `<head>` spliced into the `<html>` element, for
//      layouts that have no `<head>` at all (e.g. App Router root layouts
//      that rely solely on the Metadata API). Next.js merges a manually
//      rendered `<head>` with its own metadata output, so this is safe.
//   3. Nothing, for files that define neither `<head>` nor `<html>`.
//
// `<head />` / `<html />` may be authored self-closing; those are reopened
// into `<tag>…</tag>` so the markup can live as a real child. Idempotent:
// re-running on output finds the injected meta and no-ops.
// ---------------------------------------------------------------------------

function findFirstJSXElement(
  program: unknown,
  tagName: string,
): JSXElement | null {
  let result: JSXElement | null = null;
  walk(program as Parameters<typeof walk>[0], {
    JSXElement(node: unknown) {
      if (result) return;
      const element = node as JSXElement;
      if (getTagName(element.openingElement.name) === tagName) {
        result = element;
      }
    },
  });
  return result;
}

function hasRootMetaChild(headElement: JSXElement): boolean {
  for (const child of headElement.children ?? []) {
    if (child.type !== "JSXElement") continue;
    const childTag = getTagName(child.openingElement.name);
    if (childTag !== "meta") continue;
    for (const attr of child.openingElement.attributes ?? []) {
      if (attr.type !== "JSXAttribute") continue;
      if (getTagName(attr.name) !== "name") continue;
      const value = attr.value;
      if (value && value.type === "Literal" && value.value === ROOT_META_NAME) {
        return true;
      }
    }
  }
  return false;
}

/**
 * Splice `childMarkup` in as the first child of `element`. A normal element
 * takes the markup right after its opening tag's `>`; a self-closing element
 * (`<tag … />`) is first reopened into `<tag …></tag>` so the markup has a
 * place to live.
 */
function injectFirstChildMarkup(
  source: string,
  element: JSXElement,
  childMarkup: string,
): string {
  const opening = element.openingElement;
  if (!opening.selfClosing) {
    const insertPos = opening.end;
    return source.slice(0, insertPos) + childMarkup + source.slice(insertPos);
  }
  // `<tag … />` → `<tag …>childMarkup</tag>`: drop the trailing slash on the
  // opening tag, then add a matching close tag after the injected markup.
  const tagName = getTagName(opening.name);
  const reopened = source
    .slice(opening.start, opening.end)
    .replace(/\s*\/>$/, ">");
  return (
    source.slice(0, opening.start) +
    `${reopened}${childMarkup}</${tagName}>` +
    source.slice(opening.end)
  );
}

export function injectRootMetaIntoSource(
  source: string,
  filename: string,
  root: string,
): string {
  let parseResult;
  try {
    parseResult = parseSync(filename, source);
  } catch {
    return source;
  }

  const metaTag = `<meta name="${ROOT_META_NAME}" content={${JSON.stringify(root)}} />`;

  // Preferred: drop the meta directly inside an existing <head>.
  const headElement = findFirstJSXElement(parseResult.program, "head");
  if (headElement) {
    if (hasRootMetaChild(headElement)) return source;
    return injectFirstChildMarkup(source, headElement, metaTag);
  }

  // Fallback: no <head> — wrap the meta in one and splice it into <html>.
  const htmlElement = findFirstJSXElement(parseResult.program, "html");
  if (htmlElement) {
    return injectFirstChildMarkup(
      source,
      htmlElement,
      `<head>${metaTag}</head>`,
    );
  }

  // Neither <head> nor <html>: not a document-defining file — leave untouched.
  return source;
}

/**
 * Inject the project-root meta tag into the ALREADY-ANNOTATED source. The
 * annotated source is still a parseable JSX tree (annotateFile only added
 * attributes, never changed structure), so we can find the first `<head>`
 * the same way and splice in the meta tag right after its opening tag.
 *
 * The injected meta tag itself does NOT carry `data-tempo-*` attributes —
 * it's auto-generated, has no source location, and skipping annotation here
 * avoids the position-shift problem that pre-annotation splicing introduced.
 */
export function injectRootMetaIntoAnnotatedSource(
  annotatedSource: string,
  filename: string,
  root: string,
): string {
  return injectRootMetaIntoSource(annotatedSource, filename, root);
}

// ---------------------------------------------------------------------------
// User compute-props module resolution. Cached across calls.
// ---------------------------------------------------------------------------

function loadUserComputeProps(
  modulePath: string,
  canonicalRoot: string,
): ComputeAnnotatedProps | null {
  // Resolve the user's module path against the project root. The user passes
  // a project-relative path (`./tempo-strategy.js`) or an absolute path; we
  // resolve relative to the canonical project root.
  const resolved = resolve(canonicalRoot, modulePath);
  const requireFromRoot = createRequire(`${canonicalRoot}/__tempo_loader__.js`);
  const mod = requireFromRoot(resolved);
  const fn = mod && (mod.default ?? mod);
  if (typeof fn !== "function") {
    return null;
  }
  return fn as ComputeAnnotatedProps;
}

// ---------------------------------------------------------------------------
// Loader entry point. Webpack and Turbopack both call this with the source
// as the first argument and `this` set to a LoaderContext.
// ---------------------------------------------------------------------------

function readOptions(this: LoaderContext): NextjsLoaderOptions {
  if (typeof this.getOptions === "function") {
    return this.getOptions() ?? {};
  }
  if (typeof this.query === "string") {
    return {};
  }
  return (this.query as NextjsLoaderOptions | undefined) ?? {};
}

export function nextjsLoader(this: LoaderContext, source: string): string {
  this.cacheable?.(true);

  // Defensive env-var check (primary gate is at wrapper).
  if (!process.env.TEMPO) return source;

  const cleanPath = stripQueryAndHash(this.resourcePath ?? "");
  if (!/\.(tsx|jsx)$/.test(cleanPath)) return source;
  if (isInNodeModules(cleanPath)) return source;

  const options = readOptions.call(this);

  try {
    // Lazy-init the canonical root once. Subsequent calls reuse the same value.
    if (cachedCanonicalRoot === null) {
      cachedCanonicalRoot = resolveCanonicalRoot(this.rootContext);
    }
    const canonicalRoot = cachedCanonicalRoot;

    // Lazy-resolve the user's strategy module on the first call that supplies one.
    // Re-resolve if the user's module path changes between rule registrations.
    const userModule = options.computeAnnotatedPropsModule;
    if (userModule && userModule !== cachedComputeModulePath) {
      try {
        cachedUserComputeProps = loadUserComputeProps(
          userModule,
          canonicalRoot,
        );
      } catch {
        cachedUserComputeProps = null;
      }
      cachedComputeModulePath = userModule;
    } else if (cachedUserComputeProps === undefined) {
      cachedUserComputeProps = null;
    }
    const userComputeProps = cachedUserComputeProps;

    const filepath = relative(canonicalRoot, cleanPath);
    const modifiedtsMs = Math.trunc(statSync(cleanPath).mtimeMs);
    // Hash the exact source string being transformed once per file; every
    // element in this file carries the same version token.
    const sourceVersion = sourceVersionHash(source);

    // Step 1: annotate every JSX element. The walker visits the ORIGINAL
    // source so every `data-tempo-position` is the byte offset of the JSX
    // `<` in the source file ON DISK. This keeps positions consistent with
    // what consumers (source-editor.ts, frame-preload.ts) read from disk
    // when navigating via filepath + position.
    const annotated = annotateFile(source, cleanPath, (info) =>
      computeTempoAnnotatedProps({
        info,
        filepath,
        modifiedtsMs,
        sourceVersion,
        computeAnnotatedProps: userComputeProps ?? undefined,
      }),
    );

    // Step 2: optional auto-inject of root meta into JSX <head>. Run AFTER
    // annotation so injecting the meta does not shift any element's
    // recorded position. The injected meta tag itself does NOT get
    // `data-tempo-*` attributes (it's auto-generated, has no source
    // location, and consumers don't need to navigate to it).
    let finalSource = annotated.annotatedSource;
    if (options.autoInjectRootMeta !== false) {
      finalSource = injectRootMetaIntoAnnotatedSource(
        finalSource,
        cleanPath,
        canonicalRoot,
      );
    }

    if (finalSource === source) return source;
    return finalSource;
  } catch {
    return source;
  }
}

export default nextjsLoader;
